84	inline auto spawn_qemu(const std::string& binary,
85	                       const std::string& elf,
86	                       uint16_t gdb_port) -> pid_t
87	{
88	  const pid_t pid = ::fork();
89	  if (pid < 0)
90	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
91	                             + std::strerror(errno));
92	  if (pid == 0) {
93	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
94	    std::vector<const char*> argv;
95	    argv.push_back(binary.c_str());
96	    argv.push_back("-M");
97	    argv.push_back("virt");
98	    argv.push_back("-bios");
99	    argv.push_back("none");
100	    argv.push_back("-nographic");
101	    argv.push_back("-semihosting-config");
102	    argv.push_back("enable=on,target=native");
103	    argv.push_back("-kernel");
104	    argv.push_back(elf.c_str());
105	    argv.push_back("-gdb");
106	    argv.push_back(gdb_arg.c_str());
107	    argv.push_back("-S");
108	    argv.push_back(nullptr);
109	
110	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
111	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
112	                 std::strerror(errno));
113	    ::_exit(127);
114	  }
115	  return pid;
116	}
