146	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
147	// status (or 128 + signal for abnormal termination).
148	inline auto run_qemu_handback(const std::string& qemu_binary,
149	                              const std::string& elf_path,
150	                              const hybrid_state_v1& state) -> int

150	                              const hybrid_state_v1& state) -> int
151	{
152	  const auto port = detail::pick_free_port();
153	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
154	               qemu_binary, port);
155	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port);
156	
157	  try {
158	    restore_state_via_gdbstub(port, state);
159	  } catch (...) {
160	    ::kill(pid, SIGKILL);
161	    int wstat = 0;
162	    ::waitpid(pid, &wstat, 0);
163	    throw;
164	  }
165	
166	  int wstat = 0;
167	  if (::waitpid(pid, &wstat, 0) < 0)
168	    throw std::runtime_error(std::string{"waitpid: "}
169	                             + std::strerror(errno));
170	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
171	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
172	  return -1;
173	}
